import sys
from collections import deque

class Solution:
    def solve(self) -> None:
        n = int(sys.stdin.readline())
        queue = deque(map(int, sys.stdin.readline().split()))
        while queue:
            print(queue.popleft())

if __name__ == '__main__':
    Solution().solve()

