#include <iostream>
#include <vector>

using namespace std;

void solve(vector<int>& queue) {
    while (!queue.empty()) {
        cout << queue.front() << endl;
        queue.pop_front();
    }
}

int main() {
    int n;
    cin >> n;
    vector<int> q(n);
    for (int i = 0; i < n; i++) {
        cin >> q[i];
    }

    solve(q);

    return 0;
}
